const error = $json;
const workflowName = error.workflow?.name || 'Unknown';
const nodeError    = error.execution?.error?.message || 'No message';
const nodeErrorNode = error.execution?.lastNodeExecuted || 'Unknown node';

return [{ json: {
  workflow_name: workflowName,
  error_node:    nodeErrorNode,
  error_message: nodeError,
  timestamp:     new Date().toISOString(),
  alert: `⚠️ WORKFLOW ERROR\nWorkflow: ${workflowName}\nNode: ${nodeErrorNode}\nError: ${nodeError}`,
} }];
